9	/**@ch 懸賞令排版方向設定（直/橫各一組）*/
10	@ccclass('WantedPosterLayoutConfig')
11	class WantedPosterLayoutConfig {
12	    @property({ type: Enum(Layout.Type), tooltip: "排版類型" })
13	    type = Layout.Type.VERTICAL;
14	
15	    @property({ type: Enum(Layout.ResizeMode), tooltip: "縮放模式" })
16	    resizeMode = Layout.ResizeMode.NONE;
17	
18	    @property({ tooltip: "左內距" }) paddingLeft: number = 0;
19	    @property({ tooltip: "右內距" }) paddingRight: number = 0;
20	    @property({ tooltip: "上內距" }) paddingTop: number = 0;
21	    @property({ tooltip: "下內距" }) paddingBottom: number = 0;
22	    @property({ tooltip: "水平間距" }) spacingX: number = 0;
23	    @property({ tooltip: "垂直間距" }) spacingY: number = 0;
24	    @property({ tooltip: "水平對齊（GRID 模式有效）" }) alignHorizontal: boolean = false;
25	    @property({ tooltip: "垂直對齊（GRID 模式有效）" }) alignVertical: boolean = false;
26	}
