28	/**@ch 懸賞令管理器事件*/
29	export const WANTED_POSTER_MANAGER_EVENT = {
30	    /**
31	     * @ch 設置懸賞令資料
32	     * @param IBountyData[] 懸賞令資料陣列
33	     */
34	    SET_WANTED_POSTER_DATA: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_DATA",
35	
36	    /**
37	     * @ch 設置懸賞令UI顯示狀態
38	     * @param isShow 是否顯示
39	     */
40	    SET_WANTED_POSTER_UI_SHOW: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_UI_SHOW",
41	
42	    /**
43	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark → Mark_Idle loop
44	     * @param baseSymbol number 對應的 BaseSymbol（M1~M9）
45	     * @param resolve () => void 播完 Mark 後呼叫（Mark_Idle 已在 spine 上 loop）
46	     */
47	    PLAY_MARK: "WANTED_POSTER_MANAGER_PLAY_MARK",
48	
49	    /**
50	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark_Active 並關閉 item
51	     * @param baseSymbol number 對應的 BaseSymbol
52	     * @param resolve () => void 播完 Mark_Active 且 item.active=false 後呼叫
53	     */
54	    PLAY_MARK_ACTIVE: "WANTED_POSTER_MANAGER_PLAY_MARK_ACTIVE",
55	    
56	    /**
57	     * @ch 遊戲介紹完成後顯示懸賞令x9999
58	     */
59	    GAME_INTRO_COMPLETE: "WANTED_POSTER_MANAGER_GAME_INTRO_COMPLETE",
60	}
